const input = $input.first().json;

const out =
  input.output ||
  input.text ||
  input.response ||
  input.message ||
  input.result ||
  "Je n'ai pas pu produire de réponse.";

return [
  {
    json: {
      reply: String(out),
      suggestions: [
        "Quels centres sont à risque ?",
        "Quelles décisions recommandes-tu ?",
        "Explique-moi l’impact économique",
        "Pourquoi l’IA est meilleure que la méthode Excel ?"
      ],
      actions: [
        {
          label: "Générer un rapport d'analyse",
          type: "report",
          prompt: "Génère un rapport d'analyse structuré de la situation actuelle."
        }
      ]
    }
  }
];
